import { ChangeEvent } from 'react';
import { PublicActionPage } from '@domain/publicActionPage';
import { AutoSuggestInput } from '@ui/components/AutoSuggestInput';
import { InputControlProps } from '../../InputControl/InputControl';
import { AddressPredictionContent } from './AddressPredictionContent';
import { SmartyAddress } from './types';
import { useSmartyAddressInput } from './useSmartyAddressInput';

export type SmartyAddressInputProps = InputControlProps & {
  accountSlug?: string;
  actionPage?: PublicActionPage;
  disabledAutoSuggest?: boolean;
  onChange: (e: ChangeEvent<HTMLInputElement>) => void;
  onSelectAddress: (address: SmartyAddress) => void;
  value?: string;
};

export const SmartyAddressInput = ({
  accountSlug,
  actionPage,
  onChange,
  onSelectAddress,
  ...rest
}: SmartyAddressInputProps) => {
  const {
    getFormattedAddress,
    handleChange,
    handleSelectAddress,
    isAddressLoading,
    query,
    suggestions,
    verifyAddressError,
  } = useSmartyAddressInput({
    accountSlug: accountSlug ?? actionPage?.account?.slug,
    onChange,
    onSelectAddress,
  });

  return (
    <AutoSuggestInput
      isInvalid={!!verifyAddressError}
      isLoading={isAddressLoading}
      items={suggestions}
      onChange={handleChange}
      onItemSelected={handleSelectAddress}
      renderItem={(item) => (
        <AddressPredictionContent query={query} suggestion={getFormattedAddress(item, true)} />
      )}
      value={query}
      {...rest}
    />
  );
};
