   */
  onChange: (e: ChangeEvent<HTMLInputElement>) => void;

  /**
   * `onItemSelected` is called whenever an item is selected. It can be triggered at the same time
   * as `onChange` and is intended for more complex actions such as auto-filling other fields as a result of
   * item selection
   */
  onItemSelected?: (item: T) => void;

  /**
   * `renderItem` is used to render provided items into the autosuggest popover
   */
  renderItem: (item: T) => ReactNode;

  value?: string;
};

interface ItemProps {
  active: boolean;
  children: React.ReactNode;
  ref?: Ref<HTMLButtonElement>;
}

