import { ChangeEventHandler, forwardRef, ReactNode } from 'react';
import { Input, InputProps, useBoolean } from '@chakra-ui/react';
import { FormControl } from '../FormControl';
import { handleMaxCharacterCountInput, MaxCharacterCount } from '../MaxCharacterCount';
import { BaseProps } from '../baseProps';
import { ConditionalInputGroup } from './components';

export type InputControlProps = BaseProps &
  InputProps & {
    inputLeftElement?: ReactNode;
    inputRightElement?: ReactNode;
    interactiveRightElement?: boolean;
    isTouched?: boolean;
    maxCharacterCount?: number;
  };

export const InputControl = forwardRef<HTMLInputElement, InputControlProps>((props, ref) => {
  const [isFocused, { off: blur, on: focus }] = useBoolean();
  const {
    formControlProps,
    formHelperText,
    inputGroupProps,
    inputLeftElement,
    inputRightElement,
    interactiveRightElement,
    isInvalid,
    isRequired,
    isTouched,
    label,
    maxCharacterCount,
    name,
    onChange,
    placeholder,
    size,
    testid,
    type = 'text',
    value,
    variant = 'floating',
    ...inputProps
  } = props;

  const safeIsTouched = isTouched === undefined || isTouched;

  const handleOnChange: ChangeEventHandler<HTMLInputElement> = (e) => {
    if (onChange) {
      if (maxCharacterCount) {
        e.target.value = handleMaxCharacterCountInput(maxCharacterCount, e.target.value);
      }
      onChange(e);
    }
  };

  const controlProps = {
    formHelperText: maxCharacterCount ? (
      <MaxCharacterCount maxCharacterCount={maxCharacterCount} value={value} />
    ) : (
      formHelperText
    ),
    isInvalid,
    isRequired,
    label,
    name,
    testid,
    variant,
    ...formControlProps,
  };

  const conditionalInputGroupProps = {
    hasValue: !!value,
    inputGroupProps,
    inputLeftElement,
    inputRightElement,
    interactiveRightElement,
    isFocused,
    size,
    type,
    variant,
  };

  const baseInputProps = {
    'data-testid': testid,
    id: name,
    isInvalid: isInvalid && safeIsTouched,
    name,
    onChange: handleOnChange,
    placeholder: variant === 'floating' ? ' ' : placeholder,
    size,
    type,
    value: type === 'text' && value === null ? '' : value,
    variant,
    ...inputProps,
    ref,
  };

  if (variant === 'floating' || variant === 'permafloating') {
    return (
      <ConditionalInputGroup {...conditionalInputGroupProps}>
        <FormControl {...controlProps} onBlur={blur} onFocus={focus}>
          <Input {...baseInputProps} />
        </FormControl>
      </ConditionalInputGroup>
    );
  }

  return (
    <FormControl onBlur={blur} onFocus={focus} {...controlProps}>
      <ConditionalInputGroup {...conditionalInputGroupProps}>
        <Input {...baseInputProps} />
      </ConditionalInputGroup>
    </FormControl>
  );
});
