export function Tooltip({ children, ...options }: { children: ReactNode } & TooltipOptions) {
  // This can accept any props as options, e.g. `placement`,
  // or other positioning options.
  const tooltip = useTooltip(options);
  return <TooltipContext.Provider value={tooltip}>{children}</TooltipContext.Provider>;
}

export const TooltipTrigger = forwardRef<
  HTMLElement,
  HTMLProps<HTMLElement> & { asChild?: boolean }
>(function TooltipTrigger({ asChild = false, children, ...props }, propRef) {
  const { getReferenceProps, isOpen, refs } = useTooltipContext();
  const childrenRef = (children as RefAttributes<ReactNode>)?.ref;
  const ref = useMergeRefs([refs.setReference, propRef, childrenRef]);

  // `asChild` allows the user to pass any element as the anchor
  if (asChild && isValidElement(children)) {
    return cloneElement(
      children,
      getReferenceProps({
        ref,
        ...props,
        ...children.props,
        'data-state': isOpen ? 'open' : 'closed',
      })
    );
  }

  return (
    <button
      data-state={isOpen ? 'open' : 'closed'}
      data-testid="tooltip-trigger"
      // The user can style the trigger based on the state
      ref={ref}
      {...getReferenceProps(props)}
      type="button"
    >
      {children}
    </button>
  );
});

export const TooltipContent = forwardRef<HTMLDivElement, HTMLProps<HTMLDivElement>>(
  function TooltipContent({ className, style, ...props }, propRef) {
    const { arrowRef, context, floatingStyles, getFloatingProps, hasArrow, isOpen, refs, variant } =
      useTooltipContext();
    const ref = useMergeRefs([refs.setFloating, propRef]);
    const { isMounted, status } = useTransitionStatus(context, { duration: 75 });

    if (!isOpen && !isMounted) {
      return null;
    }

    const classes = clsx(
      className && className,
      TOOLTIP_CONTENT_CLASSES,
      variant && TOOLTIP_VARIANT_CLASSES[variant]
    );

    return (
      <FloatingPortal>
        {isMounted && (
          <div className="min-w-max" ref={ref} style={{ ...floatingStyles }}>
            {hasArrow && (
              <FloatingArrow
                className="opacity-50 transition-opacity duration-100 ease-linear data-[status=close]:opacity-[0.6]
                  data-[status=open]:opacity-100"
                context={context}
                data-status={status}
                fill="#2D3748"
                ref={arrowRef}
              />
            )}

            <div
